document.addEventListener("DOMContentLoaded",(()=>{let e=document.querySelector(".sw-payment-link-container"),t=document.querySelector(".sw-payment-intro");if(e&&t){t.style.display="flex",t.style.flexDirection="row",t.style.justifyContent="space-evenly",e.style.display="none";let n=document.createElement("button");n.textContent="Show",n.style.width="20%",n.style.backgroundColor="#ffffff",n.style.border="solid blue 1px",n.style.color="#000000",n.style.cursor="pointer",n.style.borderRadius="5px",n.style.fontWeight="bold",t.appendChild(n),n.addEventListener("click",(()=>{"Show"===n.textContent?(n.textContent="Hide",e.style.display="block"):(n.textContent="Show",e.style.display="none")}))}}));